35	const TRACKGENTIC_DIR = ".trackgentic";
36	
37	/**
38	 * Default config.json contents.
39	 */
40	const DEFAULT_CONFIG: ConfigFile = {
41	  auth: {
42	    mode: "open",
43	    defaultUser: "anonymous",
44	  },
45	};
46	
47	/**
48	 * Default index.json contents.
49	 */
50	const DEFAULT_INDEX: IndexFile = {
51	  open: [],
52	  closed: [],
53	  childrenOf: {},
54	};
55	
56	/**
57	 * Default dependencies.json contents.
58	 */
59	const DEFAULT_DEPENDENCIES: DependenciesFile = {
60	  blockedBy: {},
61	  blocks: {},
62	};
63	
64	/**
65	 * Default users.json contents.
66	 */
67	const DEFAULT_USERS: UsersFile = {
68	  users: [],
69	};
70	
71	/**
72	 * Generate a token: tk_ + 8 random alphanumeric characters.
73	 */
74	function generateToken(): string {
75	  return `tk_${Math.random().toString(36).slice(2, 10)}`;
76	}
